var CONVERSATIONS_SQ_NL = [
{ title: "Duke porositur në një kafene në Amsterdam", scene: "Je në një kafene pranë një kanali në Amsterdam. Do të porosisësh kafe dhe diçka të vogël për mëngjes.", lines: [{ who: "them", nl: "Goedemorgen, wat wilt u bestellen?", sq: "Mirëmëngjes, çfarë dëshironi të porosisni?" }, { who: "you", nl: "Goedemorgen, ik wil graag een koffie.", sq: "Mirëmëngjes, do të doja një kafe." }, { who: "them", nl: "Met melk of zonder melk?", sq: "Me qumësht apo pa qumësht?" }, { who: "you", nl: "Met melk, graag.", sq: "Me qumësht, ju lutem." }, { who: "them", nl: "Wilt u ook iets eten?", sq: "Dëshironi edhe diçka për të ngrënë?" }, { who: "you", nl: "Ja, een broodje kaas, alstublieft.", sq: "Po, një sanduiç me djathë, ju lutem." }, { who: "them", nl: "Dat is samen acht euro.", sq: "Kjo është gjithsej tetë euro." }, { who: "you", nl: "Kan ik met kaart betalen?", sq: "A mund të paguaj me kartë?" }, { who: "them", nl: "Ja, natuurlijk.", sq: "Po, sigurisht." }, { who: "you", nl: "Dank je wel.", sq: "Faleminderit shumë." }, { who: "them", nl: "Graag gedaan, fijne dag!", sq: "Me kënaqësi, ditë të mbarë!" }] },
{ title: "Check-in në hotel në Roterdam", scene: "Ke mbërritur në një hotel në Roterdam pas udhëtimit me tren. Duhet të konfirmosh rezervimin dhe të pyesësh për mëngjesin.", lines: [{ who: "them", nl: "Goedenavond, welkom in ons hotel.", sq: "Mirëmbrëma, mirë se erdhët në hotelin tonë." }, { who: "you", nl: "Goedenavond, ik heb een reservering.", sq: "Mirëmbrëma, kam një rezervim." }, { who: "them", nl: "Op welke naam?", sq: "Në cilin emër?" }, { who: "you", nl: "Op naam van Cannon.", sq: "Në emër të Cannon." }, { who: "them", nl: "Mag ik uw paspoort zien?", sq: "A mund ta shoh pasaportën tuaj?" }, { who: "you", nl: "Ja, natuurlijk.", sq: "Po, sigurisht." }, { who: "them", nl: "Uw kamer is op de derde verdieping.", sq: "Dhoma juaj është në katin e tretë." }, { who: "you", nl: "Is ontbijt inbegrepen?", sq: "A përfshihet mëngjesi?" }, { who: "them", nl: "Ja, ontbijt is van zeven tot tien uur.", sq: "Po, mëngjesi është nga ora shtatë deri në dhjetë." }, { who: "you", nl: "Waar is de lift?", sq: "Ku është ashensori?" }, { who: "them", nl: "De lift is rechts naast de receptie.", sq: "Ashensori është djathtas pranë recepsionit." }] },
{ title: "Duke kërkuar drejtim për në stacion", scene: "Je në qendër të Utrehtit dhe duhet të gjesh stacionin e trenit. Ndalon një vendas dhe pyet me mirësjellje.", lines: [{ who: "you", nl: "Sorry, mag ik iets vragen?", sq: "Më fal, a mund të pyes diçka?" }, { who: "them", nl: "Ja, natuurlijk.", sq: "Po, sigurisht." }, { who: "you", nl: "Waar is het station?", sq: "Ku është stacioni?" }, { who: "them", nl: "Ga rechtdoor en sla dan linksaf.", sq: "Shko drejt dhe pastaj kthehu majtas." }, { who: "you", nl: "Is het ver?", sq: "A është larg?" }, { who: "them", nl: "Nee, ongeveer tien minuten lopen.", sq: "Jo, rreth dhjetë minuta në këmbë." }, { who: "you", nl: "Kunt u het op de kaart tonen?", sq: "A mund ta tregoni në hartë?" }, { who: "them", nl: "Ja, het is hier, bij de brug.", sq: "Po, është këtu, pranë urës." }, { who: "you", nl: "Dank u voor uw hulp.", sq: "Faleminderit për ndihmën tuaj." }, { who: "them", nl: "Geen probleem, fijne reis!", sq: "S’ka problem, udhëtim të mbarë!" }] },
{ title: "Darkë në një restorant në Haga", scene: "Je në një restorant në Haga dhe dëshiron një tavolinë për dy. Pyet për rekomandim dhe porosit darkë.", lines: [{ who: "them", nl: "Goedenavond, heeft u gereserveerd?", sq: "Mirëmbrëma, a keni rezervuar?" }, { who: "you", nl: "Nee, heeft u een tafel voor twee?", sq: "Jo, a keni tavolinë për dy?" }, { who: "them", nl: "Ja, volgt u mij maar.", sq: "Po, më ndiqni ju lutem." }, { who: "you", nl: "Dank u, mogen we het menu zien?", sq: "Faleminderit, a mund ta shohim menunë?" }, { who: "them", nl: "Natuurlijk, hier is het menu.", sq: "Sigurisht, ja ku është menuja." }, { who: "you", nl: "Wat raadt u aan?", sq: "Çfarë rekomandoni?" }, { who: "them", nl: "De vis is vandaag erg goed.", sq: "Peshku është shumë i mirë sot." }, { who: "you", nl: "Dan neem ik de vis en wat water.", sq: "Atëherë do marr peshkun dhe pak ujë." }, { who: "them", nl: "Prima, wilt u brood erbij?", sq: "Në rregull, dëshironi bukë me të?" }, { who: "you", nl: "Ja, graag.", sq: "Po, ju lutem." }, { who: "them", nl: "Komt eraan.", sq: "Po vjen menjëherë." }] },
{ title: "Duke blerë biletë treni", scene: "Je në stacion dhe do të udhëtosh nga Amsterdam në Delft. Nuk je i sigurt për platformën dhe kërkon ndihmë.", lines: [{ who: "them", nl: "Goedemiddag, kan ik u helpen?", sq: "Mirëdita, a mund t’ju ndihmoj?" }, { who: "you", nl: "Ja, ik wil een kaartje naar Delft.", sq: "Po, dua një biletë për në Delft." }, { who: "them", nl: "Enkele reis of retour?", sq: "Vetëm vajtje apo vajtje-ardhje?" }, { who: "you", nl: "Retour, alstublieft.", sq: "Vajtje-ardhje, ju lutem." }, { who: "them", nl: "Dat kost twintig euro.", sq: "Kjo kushton njëzet euro." }, { who: "you", nl: "Kan ik met kaart betalen?", sq: "A mund të paguaj me kartë?" }, { who: "them", nl: "Ja, u kunt hier pinnen.", sq: "Po, mund të paguani me kartë këtu." }, { who: "you", nl: "Van welk perron vertrekt de trein?", sq: "Nga cila platformë niset treni?" }, { who: "them", nl: "Van perron vijf.", sq: "Nga platforma pesë." }, { who: "you", nl: "Dank u wel.", sq: "Faleminderit shumë." }, { who: "them", nl: "Graag gedaan.", sq: "Me kënaqësi." }] },
{ title: "Në një dyqan rrobash", scene: "Je në një dyqan në Eindhoven dhe kërkon një xhaketë për mot me shi. Do të provosh një madhësi tjetër dhe të pyesësh për çmimin.", lines: [{ who: "them", nl: "Hallo, kan ik u helpen?", sq: "Përshëndetje, a mund t’ju ndihmoj?" }, { who: "you", nl: "Ja, ik zoek een jas.", sq: "Po, po kërkoj një xhaketë." }, { who: "them", nl: "Voor regen of voor kou?", sq: "Për shi apo për të ftohtë?" }, { who: "you", nl: "Voor regen, alstublieft.", sq: "Për shi, ju lutem." }, { who: "them", nl: "Deze jas is waterdicht.", sq: "Kjo xhaketë është kundër ujit." }, { who: "you", nl: "Mag ik deze passen?", sq: "A mund ta provoj këtë?" }, { who: "them", nl: "Ja, de paskamer is daar.", sq: "Po, kabina e provës është atje." }, { who: "you", nl: "Heeft u een grotere maat?", sq: "A keni një madhësi më të madhe?" }, { who: "them", nl: "Ja, ik haal die voor u.", sq: "Po, po e marr për ju." }, { who: "you", nl: "Hoeveel kost de jas?", sq: "Sa kushton xhaketa?" }, { who: "them", nl: "Hij kost vijfenveertig euro.", sq: "Kushton dyzet e pesë euro." }] },
{ title: "Në farmaci për dhimbje koke", scene: "Nuk ndihesh mirë pas një dite të gjatë ecjeje në Amsterdam. Hyn në farmaci dhe kërkon diçka për dhimbje koke.", lines: [{ who: "them", nl: "Goedemiddag, waarmee kan ik u helpen?", sq: "Mirëdita, me çfarë mund t’ju ndihmoj?" }, { who: "you", nl: "Ik voel me niet goed.", sq: "Nuk ndihem mirë." }, { who: "them", nl: "Wat is het probleem?", sq: "Cili është problemi?" }, { who: "you", nl: "Ik heb hoofdpijn.", sq: "Kam dhimbje koke." }, { who: "them", nl: "Heeft u koorts?", sq: "A keni temperaturë?" }, { who: "you", nl: "Nee, geen koorts.", sq: "Jo, nuk kam temperaturë." }, { who: "them", nl: "Heeft u een allergie?", sq: "A keni ndonjë alergji?" }, { who: "you", nl: "Nee, ik heb geen allergie.", sq: "Jo, nuk kam alergji." }, { who: "them", nl: "Dan kunt u dit medicijn nemen.", sq: "Atëherë mund të merrni këtë ilaç." }, { who: "you", nl: "Is dit zonder recept?", sq: "A është kjo pa recetë?" }, { who: "them", nl: "Ja, dit is zonder recept.", sq: "Po, kjo është pa recetë." }] },
{ title: "Bisedë e vogël me një vendas në Leiden", scene: "Je ulur në një kafene në Leiden dhe nis bisedë me një vendas. Dëshiron të flasësh për qytetin dhe të marrësh një rekomandim.", lines: [{ who: "you", nl: "Hallo, mag ik iets vragen?", sq: "Përshëndetje, a mund të pyes diçka?" }, { who: "them", nl: "Ja hoor, natuurlijk.", sq: "Po patjetër, sigurisht." }, { who: "you", nl: "Ik ben op vakantie en ik vind deze stad mooi.", sq: "Jam me pushime dhe mendoj se ky qytet është i bukur." }, { who: "them", nl: "Dank je, Leiden is echt gezellig.", sq: "Faleminderit, Leiden është vërtet i këndshëm." }, { who: "you", nl: "Bent u hier geboren?", sq: "A keni lindur këtu?" }, { who: "them", nl: "Ja, ik woon hier al mijn hele leven.", sq: "Po, kam jetuar këtu gjithë jetën." }, { who: "you", nl: "Wat raadt u aan in de stad?", sq: "Çfarë rekomandoni në qytet?" }, { who: "them", nl: "Bezoek de grachten en het oude centrum.", sq: "Vizitoni kanalet dhe qendrën e vjetër." }, { who: "you", nl: "Dat klinkt goed.", sq: "Kjo tingëllon mirë." }, { who: "them", nl: "En probeer ook een lokaal café.", sq: "Dhe provoni edhe një kafene lokale." }, { who: "you", nl: "Dank je wel voor de tip.", sq: "Faleminderit shumë për këshillën." }, { who: "them", nl: "Graag gedaan, veel plezier!", sq: "Me kënaqësi, kalofsh mirë!" }] }
];
